const input = $input.first().json;
const body = input.body ?? input;
const required = ['event_id', 'gym_id', 'instance', 'sender_phone', 'audience', 'message'];
const missing = required.filter((key) => !body[key]);
const base = { event_id: body.event_id ?? null, recipient_phone: body.sender_phone ?? '', metadata: { provider_message_id: body.provider_message_id ?? null, gym_id: body.gym_id ?? null, instance: body.instance ?? null, dedupe_key: body.provider_message_id ?? body.event_id ?? null } };
if (missing.length) {
  return [{ json: { ...base, status: 'needs_clarification', action: 'no_reply', message: '', risk: 'low', approval_required: false, metadata: { ...base.metadata, missing } } }];
}
const audience = body.audience === 'internal' ? 'internal' : 'external';
const text = String(body.message || '').toLowerCase();
const sensitiveExternal = ['cancelar', 'contrato', 'cobranca', 'pagamento', 'senha', 'token', 'excluir', 'apagar', 'juridico', 'dados pessoais', 'producao'];
const highRiskInternal = ['apagar', 'excluir', 'desativar', 'ativar workflow', 'producao', 'broadcast', 'disparo em massa', 'enviar para'];
if (audience === 'internal') {
  const highRisk = highRiskInternal.some((word) => text.includes(word));
  if (highRisk) {
    return [{ json: { ...base, status: 'pending_approval', action: 'no_reply', message: 'Acao interna sensivel preparada e aguardando aprovacao.', risk: 'high', approval_required: true, metadata: { ...base.metadata, audience, route: 'internal_operator_agent', role: body.context?.role ?? 'VIEWER' } } }];
  }
  return [{ json: { ...base, status: 'success', action: 'send_reply', message: 'Recebi o comando interno. Vou operar em modo seguro e registrar a execucao.', risk: 'low', approval_required: false, metadata: { ...base.metadata, audience, route: 'internal_operator_agent', role: body.context?.role ?? 'VIEWER' } } }];
}
const sensitive = sensitiveExternal.some((word) => text.includes(word));
if (sensitive) {
  return [{ json: { ...base, status: 'success', action: 'handoff', message: 'Recebi sua mensagem e vou acionar a equipe da academia para te responder com seguranca.', risk: 'medium', approval_required: false, metadata: { ...base.metadata, audience, route: 'external_service_agent', handoff_reason: 'sensitive_or_account_request' } } }];
}
return [{ json: { ...base, status: 'success', action: 'send_reply', message: 'Recebi sua mensagem. Posso te ajudar com informacoes gerais por aqui; para dados da sua conta, a equipe assume.', risk: 'low', approval_required: false, metadata: { ...base.metadata, audience, route: 'external_service_agent', same_recipient_only: true } } }];
